#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#ifndef fp
#define fp float
#endif

#ifndef EQUATIONS
#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 18
#endif

extern int device_id_inuse;
extern int platform_id_inuse;

extern long long get_time();

int solver(fp **y,
           fp *x,
           int xmax,
           fp *params,
           fp *com,
           fp *d_initvalu,
           fp *d_finavalu,
           fp *d_params,
           fp *d_com);

static void fatal_cuda(cudaError_t error, int line_no) {
    if (error != cudaSuccess) {
        printf("Error at line %d: %s\n", line_no, cudaGetErrorString(error));
        exit((int)error);
    }
}

int
kernel_gpu_opencl_wrapper( int xmax,
                           int workload,
                           fp ***y,
                           fp **x,
                           fp **params,
                           fp *com)
{
    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long timecopyin = 0;
    long long timekernel = 0;
    long long timecopyout = 0;
    long long timeother;

    time0 = get_time();

    int i;

    cudaError_t error;

    int device_count = 0;
    error = cudaGetDeviceCount(&device_count);
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    printf("Platform: NVIDIA CUDA\n");

    if (device_count <= 0) {
        printf("Error at line %d: no CUDA devices found\n", __LINE__);
        exit(1);
    }

    if (device_id_inuse < 0 || device_id_inuse >= device_count) {
        device_id_inuse = 0;
    }

    error = cudaSetDevice(device_id_inuse);
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    cudaDeviceProp prop;
    error = cudaGetDeviceProperties(&prop, device_id_inuse);
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }
    printf("Device: %s\n", prop.name);

    (void)platform_id_inuse;

    time1 = get_time();

    fp *d_initvalu;
    error = cudaMalloc((void **)&d_initvalu, EQUATIONS * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    fp *d_finavalu;
    error = cudaMalloc((void **)&d_finavalu, EQUATIONS * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    fp *d_params;
    error = cudaMalloc((void **)&d_params, PARAMETERS * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    fp *d_com;
    error = cudaMalloc((void **)&d_com, 3 * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    time2 = get_time();

    int status;

    for(i=0; i<workload; i++){

        status = solver( y[i],
                         x[i],
                         xmax,
                         params[i],
                         com,
                         d_initvalu,
                         d_finavalu,
                         d_params,
                         d_com);

        if(status !=0){
            printf("STATUS: %d\n", status);
        }
    }

    error = cudaDeviceSynchronize();
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    time3 = get_time();

    cudaFree(d_initvalu);
    cudaFree(d_finavalu);
    cudaFree(d_params);
    cudaFree(d_com);

    time4 = get_time();

    printf("Time spent in different stages of the application:\n");
    printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", (float) (time1-time0) / 1000000.0f, (float) (time1-time0) / (float) (time4-time0) * 100.0f);
    printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", (float) (time2-time1) / 1000000.0f, (float) (time2-time1) / (float) (time4-time0) * 100.0f);
    printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", (float) (time3-time2) / 1000000.0f, (float) (time3-time2) / (float) (time4-time0) * 100.0f);

    printf("\tGPU: COMPUTATION Components:\n");
    printf("\t%15.12f s, %15.12f % : GPU: COPY DATA IN\n", (float) (timecopyin) / 1000000.0f, (float) (timecopyin) / (float) (time4-time0) * 100.0f);
    printf("\t%15.12f s, %15.12f % : GPU: KERNEL\n", (float) (timekernel) / 1000000.0f, (float) (timekernel) / (float) (time4-time0) * 100.0f);
    printf("\t%15.12f s, %15.12f % : GPU: COPY DATA OUT\n", (float) (timecopyout) / 1000000.0f, (float) (timecopyout) / (float) (time4-time0) * 100.0f);
    timeother = time3-time2-timecopyin-timekernel-timecopyout;
    printf("\t%15.12f s, %15.12f % : GPU: OTHER\n", (float) (timeother) / 1000000.0f, (float) (timeother) / (float) (time4-time0) * 100.0f);

    printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", (float) (time4-time3) / 1000000.0f, (float) (time4-time3) / (float) (time4-time0) * 100.0f);
    printf("Total time:\n");
    printf("%.12f s\n", (float) (time4-time0) / 1000000.0f);

    return 0;
}
